{
  "module": "01-layout-navigation.md",
  "group": "01 — Layout & Navigation",
  "apiCount": 11,
  "apis": [
    {
      "name": "Tabs",
      "purpose": "Tab switching container for bottom/top tab navigation with TabContent children",
      "anchor": "tabs",
      "status": "found"
    },
    {
      "name": "TabContent",
      "purpose": "Content view for each tab within Tabs, supports string/CustomBuilder/BottomTabBarStyle tabBar",
      "anchor": "tabcontent",
      "status": "found"
    },
    {
      "name": "Column",
      "purpose": "Vertical linear layout container with optional space parameter",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "Horizontal linear layout container with optional space parameter",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "Stack container that overlays children in order, support alignContent for child alignment",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Flex",
      "purpose": "Flexbox layout container with direction, wrap, justifyContent, alignItems support",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "Scrollable container for content exceeding parent bounds, configurable scroll direction",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "List",
      "purpose": "List container with lazy loading via LazyForEach/Repeat, supports cachedCount and initialIndex",
      "anchor": "list",
      "status": "found"
    },
    {
      "name": "Grid",
      "purpose": "Grid container with rows/columns layout, supports cross-row/column GridItem via GridLayoutOptions",
      "anchor": "grid",
      "status": "found"
    },
    {
      "name": "Navigation",
      "purpose": "Root navigation view container with NavPathStack routing, title, menus, toolbar support",
      "anchor": "navigation",
      "status": "found"
    },
    {
      "name": "PageTransition",
      "purpose": "Page enter/exit transition animations via pageTransition() lifecycle hook, used with router",
      "anchor": "pagetransition",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Navigator component is deprecated since API 13 -- use Navigation with NavPathStack instead",
    "@ohos.router API is deprecated since API 18 -- recommended use Navigation component or UIContext.getRouter()",
    "BottomTabBarStyle is the standard way to create bottom icon+text tab bars (no underline, default 48vp height from API 12)",
    "Flex has secondary layout performance overhead; use Column/Row for performance-sensitive linear layouts",
    "List lazy loading requires LazyForEach or Repeat with virtualScroll; cachedCount enables pre-loading",
    "Grid performance improves significantly when GridLayoutOptions.regularSize is set even without irregular items"
  ],
  "missingApis": [
    {
      "name": "Navigator/router",
      "reason": "Navigator component is deprecated since API 13, @ohos.router is deprecated since API 18. The recommended replacement is Navigation with NavPathStack. Both are documented for legacy reference."
    }
  ]
}

{
  "module": "03-data-persistence.md",
  "group": "03 -- Data Persistence",
  "apiCount": 6,
  "apis": [
    {
      "name": "PersistentStorage",
      "purpose": "Cross-session persistent key-value storage backed by disk, bridging AppStorage to permanent storage for user config and last checkin date",
      "anchor": "persistentstorage",
      "status": "found"
    },
    {
      "name": "AppStorage",
      "purpose": "App-level reactive shared state singleton for current user and session data, accessible across all UI components",
      "anchor": "appstorage",
      "status": "found"
    },
    {
      "name": "dataPreferences (ohos.data.preferences)",
      "purpose": "Key-value preference storage for lightweight persistent settings and counters, backed by XML or GSKV files",
      "anchor": "ohosdatapreferences-用户首选项",
      "status": "found"
    },
    {
      "name": "relationalStore (ohos.data.relationalStore)",
      "purpose": "SQL-based relational database (SQLite wrapper) for structured data like courses, reservations, and inventory records",
      "anchor": "模块描述",
      "status": "found"
    },
    {
      "name": "@ohos.resourceManager",
      "purpose": "Read bundled JSON, media, string, boolean, number resources and rawfile content from the app HAP",
      "anchor": "ohosresourcemanager-资源管理",
      "status": "found"
    },
    {
      "name": "LocalStorage",
      "purpose": "Page-level scoped reactive state storage for component-local or page-isolated UI state",
      "anchor": "localstorage9",
      "status": "found"
    }
  ],
  "notableFindings": [
    "PersistentStorage must be initialized before AppStorage access to correctly bridge persisted data",
    "dataPreferences does not guarantee process concurrency safety - avoid multi-process use",
    "relationalStore single row must be under 2MB due to shared memory limits; large queries (>5000 rows) should use TaskPool",
    "Stage model apps access resourceManager via context.resourceManager without importing the module",
    "LocalStorage is page-scoped; for stage-shared LocalStorage use UIContext.getSharedLocalStorage() from API 12+",
    "Standard JS JSON.parse/stringify are language built-ins, not HarmonyOS APIs"
  ],
  "missingApis": []
}

{
  "module": "04-controls-dialogs.md",
  "group": "04 -- Controls, Dialogs & Input",
  "apiCount": 12,
  "apis": [
    {
      "name": "Button",
      "purpose": "按钮组件，支持Normal/Capsule/Circle/ROUNDED_RECTANGLE样式，用于触发操作",
      "anchor": "button",
      "status": "found"
    },
    {
      "name": "Text",
      "purpose": "文本展示组件，支持丰富样式、文本溢出、跑马灯、文本识别、文本选中复制",
      "anchor": "text",
      "status": "found"
    },
    {
      "name": "Span",
      "purpose": "Text组件的行内文本子组件，支持独立字体样式和装饰线",
      "anchor": "span",
      "status": "found"
    },
    {
      "name": "TextInput",
      "purpose": "单行文本输入框，支持多种输入类型(普通/密码/电话/邮箱等)和内联风格",
      "anchor": "textinput",
      "status": "found"
    },
    {
      "name": "TextArea",
      "purpose": "多行文本输入框，自动换行，自适应内容高度",
      "anchor": "textarea",
      "status": "found"
    },
    {
      "name": "DatePicker",
      "purpose": "滑动选择日期的组件，支持公历/农历、年-月-日/年-月/月-日模式",
      "anchor": "datepicker",
      "status": "found"
    },
    {
      "name": "TimePicker",
      "purpose": "滑动选择时间的组件，支持12/24小时制、时分/时分秒格式",
      "anchor": "timepicker",
      "status": "found"
    },
    {
      "name": "AlertDialog",
      "purpose": "警告弹窗，支持标题/副标题/消息、1-3个按钮、自定义样式和生命周期回调",
      "anchor": "警告弹窗-alertdialog",
      "status": "found"
    },
    {
      "name": "CustomDialog",
      "purpose": "通过CustomDialogController显示完全自定义内容的弹窗，支持数据双向绑定和动画",
      "anchor": "自定义弹窗-customdialog",
      "status": "found"
    },
    {
      "name": "Menu",
      "purpose": "垂直列表菜单容器，需配合bindMenu/bindContextMenu使用，支持多级菜单",
      "anchor": "menu",
      "status": "found"
    },
    {
      "name": "MenuItem",
      "purpose": "菜单选项，支持图标、文本、标签信息和二级菜单构建",
      "anchor": "menuitem",
      "status": "found"
    },
    {
      "name": "Select",
      "purpose": "下拉选择菜单组件，支持图标、Symbol图标、自定义菜单项样式",
      "anchor": "select",
      "status": "found"
    }
  ],
  "notableFindings": [
    "AlertDialog.show()从API 18起废弃，推荐使用getUIContext().showAlertDialog()避免UI上下文不明确问题",
    "自定义弹窗优先使用CustomDialog而非AlertDialog，便于样式与内容的完全自定义",
    "TextInput和TextArea默认padding为{top:8vp, right:16vp, bottom:8vp, left:16vp}",
    "Button的默认type从API 18起由Capsule变更为ROUNDED_RECTANGLE",
    "Text组件的Span子组件从API 10起可继承父组件的字体属性",
    "Menu组件必须通过bindMenu或bindContextMenu绑定使用，不支持单独声明为普通组件",
    "DatePicker和TimePicker不建议在滑动动效过程中修改属性数据"
  ],
  "missingApis": []
}

{
  "module": "05-image-file.md",
  "group": "05 — Image & File",
  "apiCount": 7,
  "apis": [
    {
      "name": "Image",
      "purpose": "显示网络/本地/沙箱图片（头像、作品集、课程图片）",
      "anchor": "image",
      "status": "found"
    },
    {
      "name": "ImageAnimator",
      "purpose": "逐帧播放图片序列动画（签到成功动效）",
      "anchor": "imageanimator",
      "status": "found"
    },
    {
      "name": "@ohos.file.picker (PhotoViewPicker)",
      "purpose": "从系统图库选择图片/视频（选择作品集照片）",
      "anchor": "ohosfilepicker-photoviewpicker",
      "status": "found"
    },
    {
      "name": "photoAccessHelper",
      "purpose": "相册管理模块 - 访问和修改媒体库数据",
      "anchor": "photoaccesshelper",
      "status": "found"
    },
    {
      "name": "@ohos.file.fs (fileIo)",
      "purpose": "文件读写/复制/目录管理（复制图片到沙箱、管理临时文件）",
      "anchor": "ohosfilefs-fileio",
      "status": "found"
    },
    {
      "name": "SaveButton",
      "purpose": "安全保存控件 - 带用户授权的保存/下载按钮",
      "anchor": "savebutton",
      "status": "found"
    },
    {
      "name": "uri (file:// URI patterns)",
      "purpose": "HarmonyOS 沙箱文件 URI 表示方式（file://bundleName/sandboxPath）",
      "anchor": "uri-file-uri-模式",
      "status": "found"
    }
  ],
  "notableFindings": [
    "PhotoViewPicker 和 DocumentViewPicker 分属不同 Kit：PhotoViewPicker 从 @kit.MediaLibraryKit 导入，DocumentViewPicker 从 @kit.CoreFileKit 导入",
    "PhotoViewPicker 返回的 photoUris 具有永久授权，可通过 photoAccessHelper.getAssets 继续操作",
    "SaveButton 是安全控件，需要用户点击授权后才能保存：API 19-授权10秒，API 20+授权1分钟",
    "Image 组件沙箱文件路径需使用 file://<bundleName>/<sandboxPath> URI 格式，通过 fileUri.getUriFromPath(path) 转换",
    "ImageAnimator 的 iterations 设为 -1 可实现无限循环动画",
    "fileIo.mkdir 从 API 11 起支持 recursion=true 递归创建目录",
    "ArkTS 卡片不支持 file:// 和 http:// 网络图片路径前缀"
  ],
  "missingApis": []
}

{
  "module": "06-animation-gesture.md",
  "group": "06 -- Animation & Gesture",
  "apiCount": 11,
  "apis": [
    {
      "name": "animateTo",
      "purpose": "显式动画 — 在闭包中改变状态变量时自动插入过渡动效",
      "anchor": "animateto",
      "status": "found"
    },
    {
      "name": "transition",
      "purpose": "组件内转场 — 组件插入/删除时的过渡动效",
      "anchor": "transition",
      "status": "found"
    },
    {
      "name": "animation (属性动画)",
      "purpose": "属性动画 — 组件属性变化时自动产生渐变过渡",
      "anchor": "animation-属性动画",
      "status": "found"
    },
    {
      "name": "keyframeAnimateTo",
      "purpose": "关键帧动画 — 指定若干关键帧状态实现分段动画",
      "anchor": "keyframeanimateto",
      "status": "found"
    },
    {
      "name": "TapGesture",
      "purpose": "点击手势 — 支持单击、双击和多次点击事件识别",
      "anchor": "tapgesture",
      "status": "found"
    },
    {
      "name": "LongPressGesture",
      "purpose": "长按手势 — 触发长按手势事件",
      "anchor": "longpressgesture",
      "status": "found"
    },
    {
      "name": "PanGesture",
      "purpose": "滑动手势 — 滑动距离达到设定值时触发",
      "anchor": "pangesture",
      "status": "found"
    },
    {
      "name": "PinchGesture",
      "purpose": "捏合手势 — 多指捏合缩放操作",
      "anchor": "pinchgesture",
      "status": "found"
    },
    {
      "name": "GestureGroup",
      "purpose": "手势组合 — 顺序/并发/互斥模式的手势识别组",
      "anchor": "gesturegroup",
      "status": "found"
    },
    {
      "name": "onClick",
      "purpose": "点击事件 — 组件被点击时触发回调",
      "anchor": "onclick",
      "status": "found"
    },
    {
      "name": "onTouch",
      "purpose": "触摸事件 — 手指触摸动作（按下/滑动/抬起）触发回调",
      "anchor": "ontouch",
      "status": "found"
    }
  ],
  "notableFindings": [
    "animateTo (global) is deprecated from API 18 — always use this.getUIContext()?.animateTo() instead",
    "keyframeAnimateTo is a UIContext instance method (API 11+), not a global function — requires UIContext instance via this.getUIContext()",
    "TransitionOptions (old transition API) deprecated from API 10 — use TransitionEffect API instead",
    "animation component attribute only applies to properties declared BEFORE it in the builder chain",
    "onClick/onTouch are universal component events, not gesture recognizers — use .gesture() only for GestureType objects"
  ],
  "missingApis": []
}
